const raw = $json.stdout;

if (!raw) {
  throw new Error('Nenhum stdout recebido do OCR');
}

const data = JSON.parse(raw);

if (data.erro) {
  throw new Error('Erro no OCR: ' + data.erro);
}

return [{ json: { texto: data.texto } }];

let texto = $json.texto || '';

// Junta palavras quebradas no fim da linha com hífen
texto = texto.replace(/-\n/g, '');

// Remove quebras de linha duplicadas
texto = texto.replace(/\n{2,}/g, '\n');

// Remove espaços e tabs duplicados
texto = texto.replace(/[ \t]+/g, ' ');

// Remove linhas com apenas lixo (menos de 3 chars não-alfanuméricos)
texto = texto.replace(/\n[^\wÀ-ÿ]{1,3}\n/g, '\n');

// Trim geral
texto = texto.trim();

return [{ json: { texto_limpo: texto } }];

var textoLimpo = $('Validar Campos Iniciais').first().json.texto_limpo;
var logsAnterior = $('Validar Campos Iniciais').first().json.logs || [];
var logs = logsAnterior.slice();
var tentativa = 1;
var ts = new Date().toISOString();

logs.push('[' + ts + '][T' + tentativa + '] Processando resposta da OpenAI (tentativa ' + tentativa + ' de 4)');

// Verificar se o no falhou (continueOnFail)
if ($json.error) {
  logs.push('[' + ts + '][T' + tentativa + '][ERRO] Falha na API OpenAI: ' + JSON.stringify($json.error));
  return [{ json: {
    texto_limpo: textoLimpo,
    dados_extraidos: {},
    campos_ok: false,
    erro: String($json.error),
    tentativa: tentativa,
    retry_count: tentativa,
    logs: logs
  } }];
}

// Extrair conteudo da resposta (multiplos formatos possiveis)
var content = '';
if ($json.content) content = $json.content;
else if ($json.message && $json.message.content) content = $json.message.content;
else if ($json.choices && $json.choices[0] && $json.choices[0].message) content = $json.choices[0].message.content;
else if ($json.text) content = $json.text;

logs.push('[' + ts + '][T' + tentativa + '] Conteudo recebido: ' + content.length + ' chars');

// Parse do JSON retornado pela IA
var dadosIA = {};
var erro_parse = null;
try {
  var limpo = content.trim();
  limpo = limpo.replace(/```json/g, '').replace(/```/g, '').trim();
  dadosIA = JSON.parse(limpo);
  logs.push('[' + ts + '][T' + tentativa + '][OK] JSON da IA parseado com sucesso');
} catch(e) {
  erro_parse = e.message;
  logs.push('[' + ts + '][T' + tentativa + '][ERRO] Falha ao parsear JSON: ' + e.message);
  logs.push('[' + ts + '][T' + tentativa + '][DEBUG] Resposta bruta: ' + content.substring(0, 300));
}

// Validar campos obrigatorios
var nomeOk = !!(dadosIA.nome_completo && dadosIA.nome_completo !== 'null' && String(dadosIA.nome_completo).trim().length > 2);
var telOk = !!(dadosIA.telefone && dadosIA.telefone !== 'null' && String(dadosIA.telefone).trim().length > 5);
var campos_ok = nomeOk && telOk && !erro_parse;

if (nomeOk) logs.push('[' + ts + '][T' + tentativa + '][OK] Nome: ' + dadosIA.nome_completo);
else logs.push('[' + ts + '][T' + tentativa + '][AVISO] Nome ausente ou invalido');

if (telOk) logs.push('[' + ts + '][T' + tentativa + '][OK] Telefone: ' + dadosIA.telefone);
else logs.push('[' + ts + '][T' + tentativa + '][AVISO] Telefone ausente ou invalido');

logs.push('[' + ts + '][T' + tentativa + '] Status: ' + (campos_ok ? 'DADOS COMPLETOS' : 'DADOS INCOMPLETOS'));

return [{ json: {
  texto_limpo: textoLimpo,
  dados_extraidos: dadosIA,
  campos_ok: campos_ok,
  erro_parse: erro_parse,
  tentativa: tentativa,
  retry_count: tentativa,
  logs: logs
} }];

var dados = $json.dados_extraidos || {};
var logs = ($json.logs || []).slice();
var ts = new Date().toISOString();
var sq = String.fromCharCode(39);
var escape = function(v) { return String(v).split(sq).join(sq + sq); };

var campos = [];
var valores = [];

if (dados.nome_completo) { campos.push('nome_completo'); valores.push(sq + escape(dados.nome_completo) + sq); }
