if (dados.telefone) { campos.push('telefone'); valores.push(sq + escape(dados.telefone) + sq); }
if (dados.localizacao) { campos.push('localizacao'); valores.push(sq + escape(dados.localizacao) + sq); }

var sql = 'INSERT INTO candidatos (' + campos.join(', ') + ') VALUES (' + valores.join(', ') + ');';

logs.push('[' + ts + '][SUCESSO] INSERT SQL montado via IA com ' + campos.length + ' campos (tentativa ' + ($json.tentativa || '?') + ')');

return [{ json: {
  sql_insert: sql,
  dados_extraidos: dados,
  logs: logs,
  tentativa: $json.tentativa || 0,
  status: 'pronto_para_salvar'
} }];

