var logs = ($json.logs || []).slice();
var tentativa = $json.tentativa || $json.retry_count || 0;
var textoLimpo = $json.texto_limpo || '';
var ts = new Date().toISOString();

logs.push('[' + ts + '][ERRO FINAL] Todas as ' + tentativa + ' tentativas de extracao via IA falharam');
logs.push('[' + ts + '][ERRO FINAL] Campos obrigatorios (nome e/ou telefone) nao puderam ser extraidos');
logs.push('[' + ts + '][ERRO FINAL] Arquivo encaminhado para fila de revisao manual');

var motivo = 'Extracao falhou apos ' + tentativa + ' tentativas: campos obrigatorios ausentes (nome e/ou telefone)';

return [{ json: {
  status: 'revisao_manual',
  motivo_erro: motivo,
  tentativas_realizadas: tentativa,
  texto_trecho: textoLimpo.substring(0, 1000),
  log_completo: logs.join('\n'),
  timestamp: ts
} }];

var sq = String.fromCharCode(39);
var escape = function(v) { return String(v).split(sq).join(sq + sq); };

var texto = escape(($json.texto_trecho || '').substring(0, 1000));
var motivo = escape($json.motivo_erro || 'Erro desconhecido');
var logTxt = escape(($json.log_completo || '').substring(0, 5000));
var tentativas = parseInt($json.tentativas_realizadas || 0);

var sql = 'INSERT INTO revisao_manual (texto_trecho, motivo_erro, log_completo, tentativas_realizadas, criado_em) VALUES (' + sq + texto + sq + ', ' + sq + motivo + sq + ', ' + sq + logTxt + sq + ', ' + tentativas + ', NOW());';

return [{ json: {
  sql_revisao: sql,
  motivo_erro: $json.motivo_erro,
  log_completo: $json.log_completo,
  tentativas: tentativas
} }];

return [{ json: {
  status: 'erro',
  mensagem: $json.motivo_erro || 'Falha no processamento',
  tentativas_realizadas: $json.tentativas,
  log_completo: $json.log_completo,
  timestamp: new Date().toISOString()
} }];

const items = $input.all();

if (items.length === 0 || !items[0].json || !items[0].json.telefone) {
  return [{ json: { existe: false, telefone: $('Extrair Telefone1').item.json.telefone } }];
}

const telefoneFormatado = items[0].json.telefone;

return [{ json: { existe: true, telefone: telefoneFormatado } }];

const texto = $('Limpar Texto').item.json.texto_limpo || '';

const regex = /(\(?\d{2}\)?)\s?[9]?\d{4}[-\s]?\d{4}/g;
const matches = texto.match(regex);

if (!matches || matches.length === 0) {
  throw new Error('Nenhum telefone encontrado no currículo.');
}

const telefone = matches[0].replace(/\D/g, '');

return [{ json: { telefone, texto_limpo: texto } }];

const content =
  $json.content ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  $json.text ||
  '';

if (!content) {
  throw new Error(
    'Não foi possível extrair o SQL da resposta da IA.\nJSON recebido: ' +
    JSON.stringify($json, null, 2)
  );
}

let sql = content.trim();
sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

const upperSql = sql.toUpperCase();
if (!upperSql.startsWith('INSERT') && !upperSql.startsWith('UPDATE')) {
  throw new Error('A IA não retornou um INSERT ou UPDATE válido.\nResposta: ' + sql);
}

return [{ json: { sql_insert: sql } }];
